+
+fn rebuild_and_terms(mut terms: Vec<Expr>) -> Option<Expr> {
+    let first = terms.pop()?;
+    Some(
+        terms
+            .into_iter()
+            .rev()
+            .fold(first, |right, left| Expr::BinaryOp {
+                left: Box::new(left),
+                op: BinaryOp::And,
+                right: Box::new(right),
+                span: Span::ZERO,
+            }),
+    )
+}
